async function tavilySearch(query, limit = 5, options = {}) {
  const apiKey = process.env.TAVILY_API_KEY || globalThis.TAVILY_API_KEY || "";
  if (!apiKey) {
    log4.warn("[tavily-search] TAVILY_API_KEY not configured \u2014 skipping Tavily search");
    return [];
  }
  const body = {
    query,
    max_results: limit,
    search_depth: "basic",
    include_answer: false,
    include_raw_content: false
  };
  if (options.startPublishedDate) {
    body.start_date = options.startPublishedDate;
  }
  if (options.endPublishedDate) {
    body.end_date = options.endPublishedDate;
  }
  for (let attempt = 1; attempt <= MAX_RETRIES3; attempt++) {
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
      const response = await fetch(TAVILY_SEARCH_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${apiKey}`
        },
        body: JSON.stringify(body),
        signal: controller.signal
      });
      clearTimeout(timeout);
      if (!response.ok) {
        const errText = await response.text();
        log4.warn("[tavily-search] API error", {
          attempt,
          maxRetries: MAX_RETRIES3,
          status: response.status,
          error: errText,
          query
        });
        if (attempt < MAX_RETRIES3) {
          await sleep4(RETRY_DELAY_MS2);
          continue;
        }
        return [];
      }
      const data = await response.json();
      if (!data.results) {
        log4.warn("[tavily-search] Response missing results field", { attempt, query });
        if (attempt < MAX_RETRIES3) {
          await sleep4(RETRY_DELAY_MS2);
          continue;
        }
        return [];
      }
      const mapped = data.results.filter((r2) => r2.url && r2.title).map((r2) => ({
        url: r2.url,
        title: r2.title || "Untitled",
        markdown: r2.content ?? "",
        description: r2.content
      }));
      log4.info(`[tavily-search] ${mapped.length} results for query: ${query}`);
      return mapped;
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      log4.warn("[tavily-search] Fetch error", { attempt, maxRetries: MAX_RETRIES3, error: msg, query });
      if (attempt < MAX_RETRIES3) await sleep4(RETRY_DELAY_MS2);
    }
  }
  return [];
}
